import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is an exponent?", a: "An exponent tells how many times a base is multiplied by itself. In 2^5, the base is 2 and the exponent is 5, so the value is 2 x 2 x 2 x 2 x 2 = 32." },
  { q: "How do you calculate negative exponents?", a: "A negative exponent means take the reciprocal. For example, 2^-3 = 1 / 2^3 = 1/8 = 0.125. The base is not negative just because the exponent is negative." },
  { q: "What are fractional exponents?", a: "Fractional exponents represent roots. For example, x^(1/2) is the square root of x, and x^(1/3) is the cube root of x. A fractional exponent such as x^(2/3) means cube root first, then square." },
  { q: "What is anything raised to the power of 0?", a: "Any nonzero number raised to the power of 0 equals 1. For example, 9^0 = 1 and (-4)^0 = 1. The expression 0^0 is treated as indeterminate in many math contexts." },
  { q: "How do you multiply numbers with the same base?", a: "When multiplying powers with the same base, add the exponents: a^m x a^n = a^(m+n). For example, 3^2 x 3^4 = 3^6 = 729." },
];

export default function ExponentCalculator() {
  const [base, setBase] = useState(2);
  const [exponent, setExponent] = useState(5);
  const [rootValue, setRootValue] = useState(81);
  const [rootIndex, setRootIndex] = useState(2);
  const result = Math.pow(base, exponent);
  const rootResult = rootIndex !== 0 ? Math.pow(rootValue, 1 / rootIndex) : 0;
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead
        title="Free Exponent Calculator Online - Calculate Any Power or Exponent Instantly | CalcHive"
        description="Free online exponent calculator. Calculate any base raised to any power including negative and fractional exponents instantly. Step by step solution shown. 100% free, no signup required."
        canonical="/exponent-calculator"
        keywords="free exponent calculator, power calculator free online, calculate exponents free, negative exponent calculator free, fractional exponent calculator free online"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Exponent Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free exponent calculator to calculate exponents free, including negative and fractional exponents.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div>
              <label htmlFor="base" className="text-sm font-semibold text-foreground block mb-2">Base</label>
              <input id="base" type="number" inputMode="decimal" value={base} onChange={(event) => setBase(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label htmlFor="exponent" className="text-sm font-semibold text-foreground block mb-2">Exponent</label>
              <input id="exponent" type="number" inputMode="decimal" step="0.01" value={exponent} onChange={(event) => setExponent(Number(event.target.value))} className={inputClass} />
            </div>
          </div>
          <motion.div key={`${base}-${exponent}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{base}^{exponent}</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-power">{Number.isFinite(result) ? Number(result.toFixed(10)).toLocaleString() : "Not real"}</p>
            </div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4">
              <p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p>
              <p className="text-sm text-foreground" data-testid="result-steps">{exponent < 0 ? `${base}^${exponent} = 1 / ${base}^${Math.abs(exponent)} = ${Number(result.toFixed(10))}` : `${base}^${exponent} = ${Number(result.toFixed(10))}`}</p>
            </div>
          </motion.div>
        </section>

        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Nth Root Calculator</h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
            <div>
              <label htmlFor="root-value" className="text-sm font-semibold text-foreground block mb-2">Value</label>
              <input id="root-value" type="number" inputMode="decimal" value={rootValue} onChange={(event) => setRootValue(Number(event.target.value))} className={inputClass} />
            </div>
            <div>
              <label htmlFor="root-index" className="text-sm font-semibold text-foreground block mb-2">Root index</label>
              <input id="root-index" type="number" inputMode="decimal" value={rootIndex} onChange={(event) => setRootIndex(Number(event.target.value))} className={inputClass} />
            </div>
          </div>
          <div className="bg-accent/60 border border-border rounded-xl p-4 text-center">
            <p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Root result</p>
            <p className="text-3xl font-extrabold text-foreground" data-testid="result-root">{Number.isFinite(rootResult) ? Number(rootResult.toFixed(10)).toLocaleString() : "Not real"}</p>
          </div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Any Exponent or Power for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Enter a base and exponent. The calculator evaluates base raised to that power instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">How Negative and Fractional Exponents Work</h2>
          <p className="text-muted-foreground leading-relaxed">Negative exponents create reciprocals. Fractional exponents represent roots, such as x^(1/2) for square root.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Powers and Exponents Tool for Students</h2>
          <p className="text-muted-foreground leading-relaxed">This power calculator free online tool helps students check exponent and root problems quickly.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/exponent-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


